 22вҶ’// --- search tool ---
 23вҶ’
 24вҶ’func searchTool() mcpgo.Tool {
 25вҶ’	return mcpgo.NewTool("search",
 26вҶ’		mcpgo.WithDescription("Search your knowledge base. Returns matching items with titles, types, tags, and content snippets."),
 27вҶ’		mcpgo.WithString("query", mcpgo.Required(), mcpgo.Description("Search query text")),
 28вҶ’		mcpgo.WithNumber("limit", mcpgo.Description("Max results to return (1-50, default 10)")),
 29вҶ’		mcpgo.WithString("type", mcpgo.Description("Filter by item type"), mcpgo.Enum("bookmark", "text_note", "voice_note")),
 30вҶ’	)
 31вҶ’}
 32вҶ’
 33вҶ’func searchHandler(deps Deps) server.ToolHandlerFunc {
 34вҶ’	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
 35вҶ’		claims, errResult := requireAuth(ctx)
 36вҶ’		if errResult != nil {
 37вҶ’			return errResult, nil
 38вҶ’		}
 39вҶ’
 40вҶ’		query := req.GetString("query", "")
 41вҶ’		if query == "" {
 42вҶ’			return mcpgo.NewToolResultError("query is required"), nil
 43вҶ’		}
 44вҶ’
 45вҶ’		limit := req.GetInt("limit", defaultSearchLimit)
 46вҶ’		if limit < 1 {
 47вҶ’			limit = 1
 48вҶ’		}
 49вҶ’		if limit > maxSearchLimit {
 50вҶ’			limit = maxSearchLimit
 51вҶ’		}
 52вҶ’
 53вҶ’		var filter *item.Filter
 54вҶ’		if t := req.GetString("type", ""); t != "" {
 55вҶ’			filter = &item.Filter{Types: []string{t}}
 56вҶ’		}
 57вҶ’
 58вҶ’		result, err := doSearch(ctx, deps, claims.UserID, query, filter, limit)
 59вҶ’		if err != nil {
 60вҶ’			return mcpgo.NewToolResultError(fmt.Sprintf("search failed: %v", err)), nil
 61вҶ’		}
 62вҶ’
 63вҶ’		return mcpgo.NewToolResultText(formatSearchResults(result)), nil
 64вҶ’	}
 65вҶ’}
