 67вҶ’// doSearch tries semantic search first, falling back to full-text search.
 68вҶ’func doSearch(ctx context.Context, deps Deps, ownerID uuid.UUID, query string, filter *item.Filter, limit int) (*item.SearchResult, error) {
 69вҶ’	if deps.Embedder != nil {
 70вҶ’		embedding, err := deps.Embedder.Embed(ctx, query)
 71вҶ’		if err != nil {
 72вҶ’			slog.WarnContext(ctx, "mcp: embedding failed, falling back to FTS", "error", err)
 73вҶ’		} else {
 74вҶ’			result, err := deps.Items.SemanticSearch(ctx, ownerID, embedding, filter, limit, defaultSearchThreshold)
 75вҶ’			if err == nil && len(result.Items) > 0 {
 76вҶ’				return result, nil
 77вҶ’			}
 78вҶ’			if err != nil {
 79вҶ’				slog.WarnContext(ctx, "mcp: semantic search failed, falling back to FTS", "error", err)
 80вҶ’			}
 81вҶ’		}
 82вҶ’	}
 83вҶ’
 84вҶ’	return deps.Items.Search(ctx, ownerID, query, filter, limit, 0)
 85вҶ’}
