119вҶ’
120вҶ’func captureTool() mcpgo.Tool {
121вҶ’	return mcpgo.NewTool("capture",
122вҶ’		mcpgo.WithDescription("Capture a new item into your knowledge base. Provide 'url' for a bookmark or 'content' for a note."),
123вҶ’		mcpgo.WithString("url", mcpgo.Description("URL to bookmark")),
124вҶ’		mcpgo.WithString("content", mcpgo.Description("Text content for a note")),
125вҶ’		mcpgo.WithString("title", mcpgo.Description("Optional title")),
126вҶ’		mcpgo.WithString("tags", mcpgo.Description("Comma-separated tags")),
127вҶ’		mcpgo.WithString("sensitivity", mcpgo.Description("Sensitivity level"), mcpgo.Enum("normal", "sensitive")),
128вҶ’	)
