131вҶ’func captureHandler(deps Deps) server.ToolHandlerFunc {
132вҶ’	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
133вҶ’		claims, errResult := requireAuth(ctx)
134вҶ’		if errResult != nil {
135вҶ’			return errResult, nil
136вҶ’		}
137вҶ’
138вҶ’		url := req.GetString("url", "")
139вҶ’		content := req.GetString("content", "")
140вҶ’		titleStr := req.GetString("title", "")
141вҶ’		tagsStr := req.GetString("tags", "")
142вҶ’		sensitivity := req.GetString("sensitivity", "normal")
143вҶ’
144вҶ’		var title *string
145вҶ’		if titleStr != "" {
146вҶ’			title = &titleStr
147вҶ’		}
148вҶ’
149вҶ’		var tags []string
150вҶ’		if tagsStr != "" {
151вҶ’			for _, t := range strings.Split(tagsStr, ",") {
152вҶ’				t = strings.TrimSpace(t)
153вҶ’				if t != "" {
154вҶ’					tags = append(tags, t)
155вҶ’				}
156вҶ’			}
157вҶ’		}
158вҶ’
159вҶ’		switch {
160вҶ’		case url != "":
161вҶ’			it, err := deps.Items.CaptureBookmark(ctx, claims.UserID, item.BookmarkInput{
162вҶ’				URL:         url,
163вҶ’				Title:       title,
164вҶ’				Tags:        tags,
165вҶ’				Sensitivity: sensitivity,
166вҶ’				Source:      "mcp",
167вҶ’			})
168вҶ’			if err != nil {
169вҶ’				return mcpgo.NewToolResultError(fmt.Sprintf("failed to capture bookmark: %v", err)), nil
170вҶ’			}
171вҶ’			return mcpgo.NewToolResultText(formatItem(it)), nil
172вҶ’
173вҶ’		case content != "":
174вҶ’			it, err := deps.Items.CaptureNote(ctx, claims.UserID, item.NoteInput{
175вҶ’				Title:       title,
176вҶ’				Content:     content,
177вҶ’				Tags:        tags,
178вҶ’				Sensitivity: sensitivity,
179вҶ’				Source:      "mcp",
180вҶ’			})
181вҶ’			if err != nil {
182вҶ’				return mcpgo.NewToolResultError(fmt.Sprintf("failed to capture note: %v", err)), nil
183вҶ’			}
184вҶ’			return mcpgo.NewToolResultText(formatItem(it)), nil
185вҶ’
186вҶ’		default:
187вҶ’			return mcpgo.NewToolResultError("either 'url' (for bookmark) or 'content' (for note) is required"), nil
188вҶ’		}
189вҶ’	}
