10вҶ’const maxSnippetLen = 500
11вҶ’
12вҶ’// formatSearchResults renders a search result set as markdown text.
13вҶ’func formatSearchResults(result *item.SearchResult) string {
14вҶ’	if len(result.Items) == 0 {
15вҶ’		return "No items found."
16вҶ’	}
17вҶ’
18вҶ’	var b strings.Builder
19вҶ’	fmt.Fprintf(&b, "Found %d item(s):\n\n", result.Total)
20вҶ’
21вҶ’	for _, it := range result.Items {
22вҶ’		b.WriteString(formatItemSummary(it))
23вҶ’		b.WriteString("\n")
24вҶ’	}
25вҶ’
26вҶ’	if result.HasMore {
27вҶ’		b.WriteString("_(more results available вҖ” increase limit or refine query)_\n")
28вҶ’	}
29вҶ’
30вҶ’	return b.String()
31вҶ’}
32вҶ’
33вҶ’// formatItemSummary renders a single item as a compact summary line.
34вҶ’func formatItemSummary(it *item.Item) string {
35вҶ’	var b strings.Builder
36вҶ’
37вҶ’	title := it.ID.String()
38вҶ’	if it.Title != nil && *it.Title != "" {
39вҶ’		title = *it.Title
40вҶ’	}
41вҶ’
42вҶ’	fmt.Fprintf(&b, "- **%s** [%s] (id: %s)", title, it.Type, it.ID)
43вҶ’
44вҶ’	if len(it.Tags) > 0 {
45вҶ’		fmt.Fprintf(&b, " tags: %s", strings.Join(it.Tags, ", "))
46вҶ’	}
47вҶ’
48вҶ’	if it.ContentText != nil && *it.ContentText != "" {
49вҶ’		snippet := *it.ContentText
50вҶ’		if len(snippet) > maxSnippetLen {
51вҶ’			snippet = snippet[:maxSnippetLen] + "..."
52вҶ’		}
53вҶ’		fmt.Fprintf(&b, "\n  > %s", strings.ReplaceAll(snippet, "\n", "\n  > "))
54вҶ’	}
55вҶ’
56вҶ’	b.WriteString("\n")
57вҶ’	return b.String()
58вҶ’}
59вҶ’
60вҶ’// formatItem renders a full item as detailed markdown.
61вҶ’func formatItem(it *item.Item) string {
62вҶ’	var b strings.Builder
63вҶ’
64вҶ’	title := it.ID.String()
65вҶ’	if it.Title != nil && *it.Title != "" {
66вҶ’		title = *it.Title
67вҶ’	}
68вҶ’
69вҶ’	fmt.Fprintf(&b, "# %s\n\n", title)
70вҶ’	fmt.Fprintf(&b, "- **ID:** %s\n", it.ID)
71вҶ’	fmt.Fprintf(&b, "- **Type:** %s\n", it.Type)
72вҶ’	fmt.Fprintf(&b, "- **Status:** %s\n", it.Status)
73вҶ’	fmt.Fprintf(&b, "- **Sensitivity:** %s\n", it.Sensitivity)
74вҶ’	fmt.Fprintf(&b, "- **Source:** %s\n", it.Source)
75вҶ’	fmt.Fprintf(&b, "- **Captured:** %s\n", it.CapturedAt.Format("2006-01-02 15:04:05"))
76вҶ’
77вҶ’	if len(it.Tags) > 0 {
78вҶ’		fmt.Fprintf(&b, "- **Tags:** %s\n", strings.Join(it.Tags, ", "))
79вҶ’	}
80вҶ’
81вҶ’	if it.SourceURL != nil && *it.SourceURL != "" {
82вҶ’		fmt.Fprintf(&b, "- **URL:** %s\n", *it.SourceURL)
83вҶ’	}
84вҶ’
85вҶ’	if it.ContentURL != nil && *it.ContentURL != "" {
86вҶ’		fmt.Fprintf(&b, "- **Content URL:** %s\n", *it.ContentURL)
87вҶ’	}
88вҶ’
89вҶ’	if it.ContentText != nil && *it.ContentText != "" {
90вҶ’		fmt.Fprintf(&b, "\n## Content\n\n%s\n", *it.ContentText)
91вҶ’	}
92вҶ’
93вҶ’	return b.String()
94вҶ’}
